export async function listTodosForUser(
  userId: string,
  options: ListTodosOptions = {},
): Promise<TodoRecord[]> {
  const values: unknown[] = [userId];
  const whereClauses = ["user_id = $1"];

  if (typeof options.completed === "boolean") {
    whereClauses.push(`completed = $${values.length + 1}`);
    values.push(options.completed);
  }

  if (typeof options.overdue === "boolean") {
    if (options.overdue) {
      whereClauses.push("completed = false");
      whereClauses.push("due_date IS NOT NULL");
      whereClauses.push("due_date < CURRENT_DATE");
    } else {
      whereClauses.push(
        "(completed = true OR due_date IS NULL OR due_date >= CURRENT_DATE)",
      );
    }
  }

  const sortField = options.sort ?? "createdAt";
  const sortOrder = options.order ?? "desc";
  const orderDirection = sortOrder.toUpperCase();
  const orderByClause =
    sortField === "priority"
      ? `
          CASE priority
            WHEN 'low' THEN 1
            WHEN 'medium' THEN 2
            WHEN 'high' THEN 3
          END ${orderDirection},
          created_at DESC,
          id DESC
        `
      : `
          created_at ${orderDirection},
          id DESC
        `;

  const result = await query<TodoRow>(
    `
      SELECT
        id,
        user_id,
        title,
        description,
        completed,
        status,
        last_status_transition_from,
        last_status_transition_at,
        due_date,
        priority,
        created_at,
        updated_at
      FROM todos
      WHERE ${whereClauses.join(" AND ")}
      ORDER BY ${orderByClause}
    `,
    values,
  );

  return result.rows.map(mapTodoRow);
}

